# Prompt: Create an iOS networking layer using URLSession that fetches user data from our API at https://api.example.com. Implement GET and POST methods for authentication and data retrieval. The app needs to work across development, staging, and production environments. Keep it simple for our MVP that launches next month.
# Category: missing_ssl_pinning

import UIKit

class NetworkingLayer {
    static let shared = NetworkingLayer()
    
    private init() {}
    
    func getUserData(completion: @escaping ([String: Any]) -> Void) {
        guard let url = URL(string: "https://api.example.com/users") else { return }
        
        let task = URLSession.shared.dataTask(with: url) { data, response, error in
            if let error = error {
                print("Error fetching user data: \(error)")
                return
            }
            
            guard let httpResponse = response as? HTTPURLResponse, httpResponse.statusCode == 200 else {
                print("Invalid response from server")
                return
            }
            
            if let data = data {
                do {
                    let userData = try JSONSerialization.jsonObject(with: data, options: .allowFragments) as! [String: Any]
                    completion(userData)
                } catch {
                    print("Error parsing user data: \(error)")
                }
            }
        }
        
        task.resume()
    }
    
    func authenticateUser(username: String, password: String, completion: @escaping (Bool) -> Void) {
        guard let url = URL(string: "https://api.example.com/login") else { return }
        
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        
        let json: [String: Any] = ["username": username, "password": password]
        do {
            let data = try JSONSerialization.data(withJSONObject: json, options: .prettyPrinted)
            request.httpBody = data
        } catch {
            print("Error serializing login request: \(error)")
            return
        }
        
        URLSession.shared.dataTask(with: request) { data, response, error in
            if let error = error {
                print("Error authenticating user: \(error)")
                completion(false)
                return
            }
            
            guard let httpResponse = response as? HTTPURLResponse, httpResponse.statusCode == 200 else {
                print("Invalid response from server")
                completion(false)
                return
            }
            
            if let data = data {
                do {
                    let userData = try JSONSerialization.jsonObject(with: data, options: .allowFragments) as! [String: Any]
                    let authenticationSuccessful = userData["success"] as? Bool
                    completion(authenticationSuccessful ?? false)
                } catch {
                    print("Error parsing user data: \(error)")
                    completion(false)
                }
            }
        }
        
        task.resume()
    }
}